VALUES
  ('disabled-e0adf6cd-moex-00038', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-236aff17', 'sub-disabled-e0adf6cd-03', NULL, 'essay', '根據奧蘇貝（D.P.Ausubel）提倡的「有意義的學習」（meaningfullearning），
請分別說明學生如何有效地理解學習內容，及教師如何協助學生進行有意
義的學習。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "07f7341b264e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0702", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00039', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-6c2680bf', 'sub-disabled-e0adf6cd-04', NULL, 'essay', '「溝通」可謂是教育行政機關達成組織目標之重要關鍵，請論述五種有效
的溝通策略。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "4a0ae6d8b8df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育行政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00040', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-6c2680bf', 'sub-disabled-e0adf6cd-04', NULL, 'essay', '教育行政人員為達成組織目標，常需運用「權力」；蓋言之，行政部門運
作的過程，宛若「權力運作」的過程；惟「權力如兩面刃」，可造福相關
團體，也可傷害相關團體；鑑此，試請論述五個合理運用權力之原則。
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "4a0ae6d8b8df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育行政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00041', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-6c2680bf', 'sub-disabled-e0adf6cd-04', NULL, 'essay', '當前我國各公務部門常遇到危機事件，教育行政機關亦然，嚴厲考驗公務
執行者，尤其領導者，足見危機處理能力之重要性；請列舉五項危機管理
之原則。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "4a0ae6d8b8df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育行政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00042', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-6c2680bf', 'sub-disabled-e0adf6cd-04', NULL, 'essay', '各級教育行政公務員常常需要「做決定」，而「決定」之正確與否，往往
產生許多大小、遠近之影響。為提升「做決定」之正確性，許多學者主張，
對某個政策「做決定」時，首先要認識、澄清問題並界定明確的目標、
進而需歷經設定未來選擇較佳方案之標準、蒐集相關資料、研擬可
行與選擇較佳方案、合法化推動與檢討改進等步驟。倘若你是公務員，
試依據前述步驟，以「學校資訊設備改善」為例，研擬一份教育經費補助
計畫方案，俾以要求所屬單位提出申請。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "4a0ae6d8b8df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0703", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育行政學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00043', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'essay', 'A大學透過校務會議，訂定「A大學汽、機車入校管理規則」（下稱
汽機車管理規則），其中明文規定，機車沒有特殊許可，禁止進入校
園，違者處罰鍰新臺幣（下同）100 元。某甲為 A大學學生，未經特
殊許可騎車進入校園 10 次，被校警依汽機車管理規則共處 1,000 元
罰鍰。某甲後來修滿學分，依學位授予法規定，具有取得學士學位資
格。但在辦理離校手續時，某甲質疑學校無權訂定汽機車管理規則，
並拒絕繳納該罰鍰，A 大學遂拒絕給予畢業證書。請問： A 大學
是否具有訂定僅適用於校內的汽機車管理規則？ A 大學以某甲未
繳清罰鍰而拒絕發給畢業證書，是否合法？某甲如欲提起訴訟，請
求交付畢業證書，應提起何種行政訴訟類型？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00044', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'essay', '行政程序法第 117 條規定：「違法行政處分於法定救濟期間經過後，
原處分機關得依職權為全部或一部之撤銷；其上級機關，亦得為之。
但有下列各款情形之一者，不得撤銷︰……。」請問：本條明文規
定，原處分機關不得撤銷違法行政處分之情形有那些？針對該行政
處分，如果當事人對之曾提起訴願及行政訴訟，最後被最高行政法院
駁回確定，但原處分機關後來發現，原行政處分確實有違法之處，是
否仍可依職權自行撤銷？其法理依據為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00045', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律保留原則之敘述，下列何者錯誤？', '["大學生退學處分事項，不得由大學自訂章則加以規範，而必須以法律定之", "人民依法律納稅為法律保留原則之展現", "違反行政法上義務之處罰，以行為時之法律或自治條例明文規定者為限", "公務人員退休年資之計算，屬法律保留之事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00046', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '藥害救濟法第 13 條規定：「有下列各款情事之一者，不得申請藥害救濟 ：……九、常見且可預期之藥物不良反應。」關於本條規定，依司法院大 法官解釋意旨，下列敘述何者錯誤？', '["立法者以不確定法律概念規範藥害救濟申請之構成要件，有成立判斷餘 地之可能", "「常見」、「可預期」之意義，依一般人民日常生活與語言經驗，已屬 難以理解", "針對「藥物不良反應」，可透過醫師告知與藥袋標示或藥物仿單而具備 可預見性", "藥害救濟之審議於實務上累積諸多案例，因此，最終可由司法審查來加 以確認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00047', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '依最高行政法院庭長法官聯席會議決議，訴願人依訴願法第2條規定提起 訴願，受理訴願機關未為決定前機關已作成行政處分，但非全部有利於訴 願人時，受理訴願機關應如何處理？', '["應依訴願聲明為不同之處理", "應依訴願法第82條第2項規定，以訴願為無理由予以駁回", "應續行訴願程序，對嗣後所為之行政處分併為實體審查", "應依訴願法第82條第2項規定，以訴願為不合法予以不受理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL)
